// // This SR latch is designed to set q high when s is high and r is low, and q_bar high when s is low and r is high.
module sr_latch (
    input s,
    input r,
    output reg q,
    output reg q_bar
);

    always @ (*) begin
        if (s && !r) begin
            q <= 1;
            q_bar <= 0;
        end else if (!s && r) begin
            q <= 0;
            q_bar <= 1;
        end
    end

endmodule
